SELECT bm.id,bm.k3_id,bm.name,bm.number,bm.image,bm.specification,bm.description1,bm.erpClsId,bm.volume,bm.inspection_report,bm.hsbm,description2,ser.name AS bcfwgys,bc.fname AS fnumber, bm.product_category,bm.fxLcp,u.user_name as creator,bm.modifier,bm.english_product_name,bm.delivery_state,bm.creator_time,bm.modification_time,bm.f_state,CONCAT(dt.dict_code, '(', dt.dict_name, ')') AS materialgroup,GROUP_CONCAT(DISTINCT bd.name) AS erpName,GROUP_CONCAT(DISTINCT bds.name) AS fxlcpName, GROUP_CONCAT(DISTINCT bdy.name) AS productName FROM by_material bm LEFT JOIN dictionary_table dt ON bm.materialgroup = dt.bilhead COLLATE utf8mb4_unicode_ci LEFT JOIN supplier ser ON bm.bcfwgys = ser.supplierid COLLATE utf8mb4_unicode_ci LEFT JOIN bd_customer bc ON bm.fnumber = bc.fnumber COLLATE utf8mb4_unicode_ci LEFT JOIN sys_user u ON bm.creator = u.k3_key COLLATE utf8mb4_unicode_ci LEFT JOIN bymaterial_dictionary bd ON bm.erpClsId = bd.kingdee AND bd.category = 'erpclsId_property' COLLATE utf8mb4_unicode_ci LEFT JOIN bymaterial_dictionary bds ON bm.fxLcp = bds.kingdee AND bds.category = 'product_type' COLLATE utf8mb4_unicode_ci LEFT JOIN bymaterial_dictionary bdy ON bm.product_category = bdy.kingdee AND bdy.category = 'product_category' COLLATE utf8mb4_unicode_ci
